#include <imgui.h>
#include <cstdio>

void DrawColorToolsExample() {
    static float text_rgba[4] = {0.95f, 0.78f, 0.22f, 1.0f};
    static float theme_rgba[4] = {0.24f, 0.52f, 0.96f, 1.0f};
    static float preview_before[4] = {0.18f, 0.20f, 0.24f, 1.0f};

    const int r = (int)(theme_rgba[0] * 255.0f);
    const int g = (int)(theme_rgba[1] * 255.0f);
    const int b = (int)(theme_rgba[2] * 255.0f);
    const int a = (int)(theme_rgba[3] * 255.0f);
    char hex_value[16] = {};
    std::snprintf(hex_value, sizeof(hex_value), "#%02X%02X%02X%02X", r, g, b, a);

    ImGui::Begin("Color Tools");
    ImGui::Text("اختر لوناً وطبقه على النص والخلفية.");
    ImGui::Separator();

    ImGui::ColorEdit4("Text Color", text_rgba);
    ImGui::ColorPicker4("Theme Color", theme_rgba);
    ImGui::ColorButton("Current", ImVec4(theme_rgba[0], theme_rgba[1], theme_rgba[2], theme_rgba[3]));
    if (ImGui::BeginDragDropSource()) {
        ImGui::SetDragDropPayload("COLOR4", theme_rgba, sizeof(float) * 4);
        ImGui::Text("اسحب اللون الحالي");
        ImGui::EndDragDropSource();
    }
    ImGui::SameLine();
    ImGui::ColorButton("Preview Before", ImVec4(preview_before[0], preview_before[1], preview_before[2], preview_before[3]));
    if (ImGui::BeginDragDropTarget()) {
        if (const ImGuiPayload* payload = ImGui::AcceptDragDropPayload("COLOR4")) {
            memcpy(preview_before, payload->Data, sizeof(float) * 4);
        }
        ImGui::EndDragDropTarget();
    }

    ImGui::Text("RGB: %d, %d, %d", r, g, b);
    ImGui::Text("RGBA: %.2f, %.2f, %.2f, %.2f", theme_rgba[0], theme_rgba[1], theme_rgba[2], theme_rgba[3]);
    ImGui::Text("HEX: %s", hex_value);
    ImGui::TextColored(ImVec4(text_rgba[0], text_rgba[1], text_rgba[2], text_rgba[3]), "هذا النص يطبق اللون المختار مباشرة.");

    ImGui::PushStyleColor(ImGuiCol_ChildBg, ImVec4(theme_rgba[0], theme_rgba[1], theme_rgba[2], 0.22f));
    ImGui::BeginChild("theme_preview", ImVec2(0.0f, 80.0f), true);
    ImGui::Text("معاينة الخلفية بعد التعديل");
    ImGui::EndChild();
    ImGui::PopStyleColor();
    ImGui::End();
}

