#include <imgui.h>
#include <cstdio>
#include <cstring>

void DrawThemeEditorExample() {
    static float accent_rgba[4] = {0.29f, 0.60f, 0.96f, 1.0f};
    static float panel_rgba[4] = {0.15f, 0.19f, 0.26f, 1.0f};
    static float background_rgba[4] = {0.08f, 0.10f, 0.15f, 1.0f};
    static float before_rgba[4] = {0.14f, 0.17f, 0.21f, 1.0f};
    static const float presets[4][4] = {
        {0.29f, 0.60f, 0.96f, 1.0f},
        {0.96f, 0.52f, 0.32f, 1.0f},
        {0.36f, 0.74f, 0.58f, 1.0f},
        {0.82f, 0.50f, 0.92f, 1.0f}
    };

    auto draw_target = [&](const char* id, float* value) {
        ImGui::ColorButton(id, ImVec4(value[0], value[1], value[2], value[3]));
        if (ImGui::BeginDragDropTarget()) {
            if (const ImGuiPayload* payload = ImGui::AcceptDragDropPayload("THEME_COLOR")) {
                std::memcpy(value, payload->Data, sizeof(float) * 4);
            }
            ImGui::EndDragDropTarget();
        }
    };

    const int r = (int)(accent_rgba[0] * 255.0f);
    const int g = (int)(accent_rgba[1] * 255.0f);
    const int b = (int)(accent_rgba[2] * 255.0f);
    char hex_value[16] = {};
    std::snprintf(hex_value, sizeof(hex_value), "#%02X%02X%02X", r, g, b);

    ImGui::Begin("Theme Editor");
    ImGui::Text("Palette presets + scene preview + multi-color roles.");
    ImGui::Separator();

    ImGui::ColorEdit4("Accent", accent_rgba);
    ImGui::SameLine();
    draw_target("accent_target", accent_rgba);

    ImGui::ColorEdit4("Panel", panel_rgba);
    ImGui::SameLine();
    draw_target("panel_target", panel_rgba);

    ImGui::ColorEdit4("Background", background_rgba);
    ImGui::SameLine();
    draw_target("background_target", background_rgba);

    ImGui::Separator();
    for (int i = 0; i < 4; ++i) {
        char preset_label[24] = {};
        std::snprintf(preset_label, sizeof(preset_label), "preset_%d", i);
        if (i > 0) ImGui::SameLine();
        ImGui::ColorButton(preset_label, ImVec4(presets[i][0], presets[i][1], presets[i][2], presets[i][3]));
        if (ImGui::BeginDragDropSource()) {
            ImGui::SetDragDropPayload("THEME_COLOR", presets[i], sizeof(float) * 4);
            ImGui::Text("اسحب هذا اللون إلى أي حقل.");
            ImGui::EndDragDropSource();
        }
    }

    ImGui::Separator();
    ImGui::Text("Accent HEX: %s", hex_value);
    ImGui::ColorButton("Before", ImVec4(before_rgba[0], before_rgba[1], before_rgba[2], before_rgba[3]));
    ImGui::SameLine();
    ImGui::ColorButton("After", ImVec4(background_rgba[0], background_rgba[1], background_rgba[2], background_rgba[3]));
    ImGui::TextColored(ImVec4(accent_rgba[0], accent_rgba[1], accent_rgba[2], accent_rgba[3]), "This title uses the current accent color.");

    ImGui::PushStyleColor(ImGuiCol_ChildBg, ImVec4(panel_rgba[0], panel_rgba[1], panel_rgba[2], 0.92f));
    ImGui::BeginChild("scene_preview", ImVec2(0.0f, 88.0f), true);
    ImGui::TextColored(ImVec4(accent_rgba[0], accent_rgba[1], accent_rgba[2], accent_rgba[3]), "Scene Panel");
    ImGui::Text("Background and panel colors reflect the active theme.");
    ImGui::EndChild();
    ImGui::PopStyleColor();
    ImGui::End();
}
